17: // Package rbac implements the authorizer.Authorizer interface using roles base access control.
18: package rbac
19: 
20: import (
21: 	"bytes"
22: 	"context"
23: 	"fmt"
24: 
25: 	"k8s.io/klog/v2"
26: 
27: 	rbacv1 "k8s.io/api/rbac/v1"
